const TEST_LIMIT = 1;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function sgTimestamp() {
  const now = new Date();
  const singaporeTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Singapore' }));
  const yyyy = singaporeTime.getFullYear();
  const mm = String(singaporeTime.getMonth() + 1).padStart(2, '0');
  const dd = String(singaporeTime.getDate()).padStart(2, '0');
  const hh = String(singaporeTime.getHours()).padStart(2, '0');
  const min = String(singaporeTime.getMinutes()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd} ${hh}:${min}`;
}

function padUnitPart(value) {
  const raw = clean(value);
  if (!raw) return '';
  if (/^\d+$/.test(raw) && raw.length === 1) return `0${raw}`;
  return raw;
}

function unitSuffix(level, unit) {
  const lvl = padUnitPart(level);
  const unt = padUnitPart(unit);

  if (lvl && unt) return `#${lvl}-${unt}`;
  if (lvl && !unt) return `#${lvl}`;
  if (!lvl && unt) return `#-${unt}`;
  return '';
}

function safeJoin(parts, separator = ' ') {
  return parts
    .map(clean)
    .filter(Boolean)
    .join(separator)
    .replace(/\s+/g, ' ')
    .trim();
}

function buildFolderName(row) {
  const recordId = clean(row['Property Record ID']);
  const segment = clean(row['Property Segment']).toLowerCase();
  const projectName = clean(row['Project Name']);
  const blk = clean(row['Blk']);
  const streetName = clean(row['Street Name']);
  const level = clean(row['Level']);
  const unit = clean(row['Unit']);
  const type = clean(row['Type']);
  const suffix = unitSuffix(level, unit);

  let base = '';

  if (segment === 'hdb') {
    base = safeJoin([blk, streetName]);
  } else if (segment === 'landed') {
    base = projectName || safeJoin([blk, streetName]) || streetName;
    if (type && !base.toLowerCase().includes(type.toLowerCase())) {
      base = `${base} - ${type}`;
    }
    // Landed records usually do not need unit suffix unless level/unit is provided.
    return safeJoin([base, suffix]) || recordId || 'Unnamed Property';
  } else {
    // Condo, commercial, industrial and fallback.
    base = projectName || safeJoin([blk, streetName]) || streetName;
  }

  return safeJoin([base, suffix]) || recordId || 'Unnamed Property';
}

const output = [];

for (const item of items) {
  const row = item.json;

  const route = clean(row['Clarity Route']);
  const automationEligible = clean(row['Automation Eligible']).toLowerCase();
  const existingLink = clean(row['Asset Folder Link']);
  const assetStatus = clean(row['Asset Folder Status']).toLowerCase();

  const isActiveRoute = route === 'Active Listing' || route === 'Active Listing + CMA';
  if (!isActiveRoute) continue;
  if (automationEligible !== 'yes') continue;
  if (existingLink) continue;
  if (assetStatus && assetStatus !== 'pending' && assetStatus !== 'error') continue;

  const folderName = buildFolderName(row);

  output.push({
    json: {
      ...row,
      'Asset Folder Name': folderName,
      'Asset Folder Last Updated': sgTimestamp(),
      'Asset Folder Notes': 'Selected for Module 3A asset folder creation test run',
    },
  });

  if (output.length >= TEST_LIMIT) break;
}

return output;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function sgTimestamp() {
  const now = new Date();
  const singaporeTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Singapore' }));
  const yyyy = singaporeTime.getFullYear();
  const mm = String(singaporeTime.getMonth() + 1).padStart(2, '0');
  const dd = String(singaporeTime.getDate()).padStart(2, '0');
  const hh = String(singaporeTime.getHours()).padStart(2, '0');
