}

const selectedRow = $('Select 1 Eligible Asset Row').first().json;
const driveResult = items[0]?.json || {};

const folderId = clean(driveResult.id);
const folderName = clean(driveResult.name || selectedRow['Asset Folder Name']);
const folderLink = clean(driveResult.webViewLink) || (folderId ? `https://drive.google.com/drive/folders/${folderId}` : '');

if (!folderId && !folderLink) {
  return [{
    json: {
      'Source Key': selectedRow['Source Key'],
      'Property Record ID': selectedRow['Property Record ID'],
      'Asset Folder Status': 'Error',
      'Asset Folder Last Updated': sgTimestamp(),
      'Asset Folder Notes': 'Google Drive folder creation did not return a folder ID or link',
    },
  }];
}

return [{
  json: {
    'Source Key': selectedRow['Source Key'],
    'Property Record ID': selectedRow['Property Record ID'],
    'Asset Folder Status': 'Created',
    'Asset Folder Link': folderLink,
    'Asset Folder Last Updated': sgTimestamp(),
    'Asset Folder Notes': `Created asset folder: ${folderName}`,
  },
}];
